UPDATE STOCBDHD SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , SIGN_STATUS = #{SIGN_STATUS}

    , SIGN_DATE = SYSDATE

 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND BID_NUM  = #{BID_NUM}
   AND BID_CNT  = #{BID_CNT}

		UPDATE STOCBDHD SET
			 BID_STATUS = #{BID_STATUS}
         WHERE GATE_CD  = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
           AND BID_NUM  = #{BID_NUM}
           AND BID_CNT  = #{BID_CNT}

		UPDATE STOCPRDT SET
              MOD_DATE    = SYSDATE
            , MOD_USER_ID = #{ses.userId}
		    , PROGRESS_CD = #{PROGRESS_CD}
         WHERE GATE_CD  = #{ses.gateCd}
           AND (BUYER_CD, PR_NUM, PR_SQ) IN (
           		SELECT BDDT.PB_BUYER_CD AS BUYER_CD
           			 , BDDT.PR_NUM
           			 , BDDT.PR_SQ
                  FROM STOCBDHD BDHD
                  JOIN STOCBDDT BDDT
                  	   ON (BDHD.GATE_CD  = BDDT.GATE_CD
                  	   AND BDHD.BUYER_CD = BDDT.BUYER_CD
                  	   AND BDHD.BID_NUM  = BDDT.BID_NUM
                  	   AND BDHD.BID_CNT  = BDDT.BID_CNT
                  	   AND BDDT.DEL_FLAG = '0')
	             WHERE BDHD.GATE_CD     = #{ses.gateCd}
	               AND BDHD.BUYER_CD    = #{BUYER_CD}
			   	   AND BDHD.APP_DOC_NUM = #{APP_DOC_NUM}
			   	   AND BDHD.APP_DOC_CNT = #{APP_DOC_CNT}
	               AND BDHD.DEL_FLAG    = '0'
	             GROUP BY BDDT.PB_BUYER_CD
	             		, BDDT.PR_NUM
	             		, BDDT.PR_SQ
               )
           AND DEL_FLAG = '0'

